package main

import (
	"context"
	"fmt"
	"log"
	"os"

	"github.com/magicbell/magicbell-go/pkg/project-client/client"
	"github.com/magicbell/magicbell-go/pkg/project-client/clientconfig"
	"github.com/magicbell/magicbell-go/pkg/project-client/users"
)

func main() {
	token := os.Getenv("MAGICBELL_PROJECT_TOKEN")
	if token == "" {
		log.Fatal("MAGICBELL_PROJECT_TOKEN is not set")
	}

	config := clientconfig.NewConfig()
	config.SetAccessToken(token)
	c := client.NewClient(config)

	params := users.ListUsersRequestParams{}
	resp, err := c.Users.ListUsers(context.Background(), params)
	if err != nil {
		log.Fatalf("Error listing users: %v", err)
	}

	fmt.Printf("Users count: %d\n", len(resp.Data.Data))
	for _, u := range resp.Data.Data {
		extID := ""
		if u.ExternalId != nil && !u.ExternalId.IsNull {
			extID = u.ExternalId.Value
		}
		email := ""
		if u.Email != nil && !u.Email.IsNull {
			email = u.Email.Value
		}
		fmt.Printf("ID: %s, ExternalId: %s, Email: %s\n", *u.Id, extID, email)
	}
}

